SELECT patient_id
FROM genetic_tests
WHERE thalassemia = 'reversible defect';

SELECT COUNT(*) AS genetic_defect_count
FROM genetic_tests
WHERE thalassemia = 'reversible defect';

SELECT risk_score
FROM predictive_analytics
WHERE patient_id = 2;

SELECT AVG(heart_rate) AS average_heart_rate, MAX(blood_pressure) AS max_blood_pressure
FROM remote_monitoring
WHERE patient_id = 1;

SELECT heart_rate, oxygen_level
FROM remote_monitoring
WHERE patient_id = 1;

SELECT MAX(timestamp) AS most_recent_timestamp
FROM remote_monitoring
WHERE patient_id = 2;

SELECT AVG(risk_score) AS average_risk_score
FROM predictive_analytics
WHERE predicted_outcome = 'High Risk';
